import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'edu-n8n-project',
  webhookToken: process.env.VEX_WEBHOOK_TOKEN
});

const result = await vex.evaluate({
  input: $input.all()[0].json.aiOutput,
  rules: [
    {
      type: 'piiDetection',
      categories: ['NAME', 'STUDENT_ID', 'EMAIL'],
      action: 'block',
      message: 'Student PII detected - FERPA violation'
    },
    {
      type: 'contentSafety',
      categories: ['HARMFUL_TO_MINORS'],
      action: 'block',
      message: 'Inappropriate content for education'
    }
  ],
  context: {
    workflowId: $workflow.id,
    studentAgeGroup: 'K-12'
  }
});

if (!result.pass) {
  throw new Error(result.message);
}

return { safeOutput: result.output };

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'edu-n8n-project' });

const toolParams = $input.all()[0].json.toolParameters;

const check = await vex.evaluate({
  input: JSON.stringify(toolParams),
  rules: [
    {
      type: 'secretsDetection',
      patterns: ['password', 'api_key', 'student_token'],
      action: 'block',
      message: 'Credentials detected in tool parameters'
    },
    {
      type: 'regexBlock',
      pattern: /\b(student|ssn|grade)\d{4,}\b/gi,
      action: 'redact',
      message: 'Sensitive student identifiers found'
    }
  ]
});

if (check.pass) {
  return { validatedParams: check.output };
} else {
  $workflow.stop('Compliance block: ' + check.message);
}

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'edu-n8n-project' });

const memoryContext = $input.all()[0].json.memoryWindow;
const executionCount = $execution.id.split('-').length;

const validation = await vex.evaluate({
  input: memoryContext,
  rules: [
    {
      type: 'loopDetection',
      maxExecutions: 5,
      action: 'block',
      message: 'Recursive workflow detected - potential infinite loop'
    },
    {
      type: 'timestampCheck',
      maxAgeHours: 24,
      field: 'conversationTimestamp',
      action: 'block',
      message: 'Stale context detected - refresh required'
    },
    {
      type: 'biasDetection',
      categories: ['GENDER_BIAS', 'RACIAL_BIAS'],
      threshold: 0.8,
      action: 'quarantine',
      message: 'Bias detected in educational content'
    }
  ]
});

return validation.pass ? { validContext: validation.output } : null;
